import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Entwickleranleitungen","description":"Unsere von der Community verfassten Leitfäden für Entwickler behandeln viele Themen, von der Erstellung eines Mods und der Einrichtung deiner Umgebung bis hin zu Rendering, Netzwerken, Datengenerierung und vielem mehr.","frontmatter":{"title":"Entwickleranleitungen","description":"Unsere von der Community verfassten Leitfäden für Entwickler behandeln viele Themen, von der Erstellung eines Mods und der Einrichtung deiner Umgebung bis hin zu Rendering, Netzwerken, Datengenerierung und vielem mehr.","authors":["IMB11","its-miroma","itsmiir"],"authors-nogithub":["basil4088"],"resources":{"https://github.com/FabricMC":"FabricMC-Organisation auf GitHub","https://github.com/FabricMC/fabric-docs/tree/main/reference/latest":"In der Dokumentation referenzierte ExampleMod"},"files":[]},"headers":[],"relativePath":"de_de/develop/index.md","filePath":"translated/de_de/develop/index.md","lastUpdated":1774711188000}`);var a={name:`de_de/develop/index.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Entwickleranleitungen <a class="header-anchor" href="#h1" aria-label="Permalink to “Entwickleranleitungen”">​</a></h1><p>Fabric ist ein leichtgewichtiger Modding-Werkzeugkasten für die Minecraft: Java Edition, die einfach und benutzerfreundlich gestaltet ist. Es ermöglicht Entwicklern, Modifikationen (&quot;Mods&quot;) am Originalspiel vorzunehmen, um neue Funktionen hinzuzufügen oder bestehende Mechaniken zu ändern.</p><p>Diese Dokumentation führt dich durch das Modding mit Fabric, von der <a href="./getting-started/creating-a-project">Erstellung deines ersten Mods</a> und der <a href="./getting-started/setting-up">Einrichtung deiner Umgebung</a> bis hin zu fortgeschrittenen Themen wie <a href="./rendering/basic-concepts">Rendering</a>, <a href="./networking">Netzwerken</a>, <a href="./data-generation/setup">Datengenerierung</a> und vielem mehr.</p><p>Sieh dir die Seitenleiste für eine Liste aller verfügbaren Seiten an.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Falls du es zu irgendeinem Zeitpunkt benötigst, steht dir ein voll funktionsfähiger Mod mit dem gesamten Quellcode dieser Dokumentation im Ordner <a href="https://github.com/FabricMC/fabric-docs/tree/main/reference/latest" target="_blank" rel="noreferrer"><code>/reference</code> auf GitHub</a> zur Verfügung.</p></div><h2 id="prerequisites" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Voraussetzungen”">​</a></h2><p>Bevor du startest mit Fabric zu modden, musst du über gewisse Kenntnisse in der Entwicklung mit Java und in der objektorientierten Programmierung im Allgemeinen verfügen.</p><p>Hier sind einige Ressourcen, die dir helfen könnten, dich mit Java und OOP vertraut zu machen:</p><ul><li><a href="https://www.w3schools.com/java/" target="_blank" rel="noreferrer">W3: Java-Tutorials</a></li><li><a href="https://www.codecademy.com/learn/learn-java" target="_blank" rel="noreferrer">Codecademy: Learn Java</a></li><li><a href="https://www.w3schools.com/java/java_oop.asp" target="_blank" rel="noreferrer">W3: Java OOP</a></li><li><a href="https://medium.com/@Adekola_Olawale/beginners-guide-to-object-oriented-programming-a94601ea2fbd" target="_blank" rel="noreferrer">Medium: Introduction to OOP</a></li></ul><h2 id="what-does-fabric-offer" tabindex="-1">Was bietet Fabric? <a class="header-anchor" href="#what-does-fabric-offer" aria-label="Permalink to “Was bietet Fabric?”">​</a></h2><p>Das Fabric-Projekt konzentriert sich auf drei Hauptkomponenten:</p><ul><li><strong>Fabric Loader</strong>: Ein flexibler, plattformunabhängiger Mod-Loader, der in erster Linie für die Minecraft: Java Edition entwickelt wurde</li><li><strong>Fabric API</strong>: Eine Reihe ergänzender APIs und Tools, die Mod-Entwickler bei der Erstellung von Mods verwenden können</li><li><strong>Fabric Loom</strong>: Ein <a href="https://gradle.org/" target="_blank" rel="noreferrer">Gradle</a> Plugin, das Entwicklern ermöglicht einfach Mods zu entwickeln und zu debuggen</li></ul><h3 id="what-does-fabric-api-offer" tabindex="-1">Was bietet die Fabric API? <a class="header-anchor" href="#what-does-fabric-api-offer" aria-label="Permalink to “Was bietet die Fabric API?”">​</a></h3><p>Die Fabric-API bietet eine Vielzahl von APIs, die auf den Standardfunktionen aufbauen und eine erweiterte oder einfachere Entwicklung ermöglichen.</p><p>Zum Beispiel bietet es neue Hooks, Events, Hilfsmittel wie transitive Zugriffserweiterungen, Zugriff auf interne Registries wie die Registry für kompostierbare Items und vieles mehr.</p>`,15)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};